GameActor = class("GameActor")

function GameActor:ctor(setting)
    local pos = StringUtil.split(setting.birthPos, "#")
    local vector3 = VectorUtil.newVector3(pos[1], pos[2], pos[3])

    self.entityId = EngineWorld:addActorNpc(vector3, setting.yaw, setting.actor, function(entity)
        entity:setCanCollided(false)
        entity:setWeight(setting.weight)
        entity:setScale(setting.scale)
        entity:setFloatProperty("textScale", setting.textScale)
        entity:setCanObstruct(false)
        entity:setHeadName(Utility.toKMBString(tostring(setting.weight), 2))
        entity:setRenderDistanceWeight(4)
        self.radius = entity:getWidth() * setting.scale * math.sqrt(2)
    end)

    self.setting = setting
    self.weight = setting.weight
    self.hp = setting.hp
    self.textScale = setting.textScale
end

function GameActor:onActorHurt(value)
    if self.hp <= 0 then
        return
    end

    self.hp = self.hp - value

    if value > 0 then
        local params = { entityId = self.entityId, damage = value }
        local data = DataBuilder.new():fromTable(params):getData()
        PacketSender:broadCastLuaCommonData("SyncActorDamage", data)
    end

    if self.hp <= 0 then
        self:destroy()
    end
end

function GameActor:getPosition()
    local entity = EngineWorld:getEntity(self.entityId)
    if entity then
        return entity:getPosition()
    end
    return VectorUtil.newVector3(0, 0, 0)
end

function GameActor:getEntityId()
    local entity = EngineWorld:getEntity(self.entityId)
    if entity then
        return entity:hashCode()
    end
	return -1
end

function GameActor:destroy()
    local entity = EngineWorld:getEntity(self.entityId)
    if entity then
        entity:unbindAllEntity()
    end

    Utility.playEffect(GameConfig.actorDestroyEffect, self:getPosition())

    LuaTimer:scheduleTimer(function()
        self:refreshActor()

        ActorManager:removeActor(self)
        EngineWorld:removeEntity(self.entityId)
    end, GameConfig.actorDestroyDelayTime, 1)
end

function GameActor:refreshActor()
    LuaTimer:scheduleTimer(function()
        --重新刷新actor
        ActorManager:addActor(GameActor.new(self.setting))
    end, GameConfig.refreshActorTime, 1)
end

function GameActor:isEntityAlive()
    local entity = EngineWorld:getEntity(self.entityId)
    if entity then
        return entity:isEntityAlive()
    end
end

function GameActor:getWeight()
    local entity = DynamicCastEntity.dynamicCastActorNpc(EngineWorld:getEntity(self.entityId))
    if entity then
        return entity:getWeight()
    end
    return 0
end

return GameActor